const input = $input.first().json;
const body = input.body && typeof input.body === 'object' ? input.body : input;
const now = new Date().toISOString();

function cleanString(value) {
  return String(value ?? '').trim();
}

function slug(value) {
  return cleanString(value)
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80);
}

function buildSourceKey(task, index) {
  const source = task.source || {};
  const channelId = cleanString(source.channel_id || source.channelId);
  const threadTs = cleanString(source.thread_ts || source.threadTs || source.message_ts || source.messageTs);
  if (channelId && threadTs) return `${channelId}:${threadTs}`;
  const title = slug(task.title || task.content || task.summary || `task-${index + 1}`);
  const date = cleanString(body.window_end || body.generated_at || now).slice(0, 10) || now.slice(0, 10);
  return `${date}:${title}`;
}

function toSlackMrkdwn(summary) {
  const headingEmoji = new Map([
    ['☀️ Morning Standup', ':sun_with_face:'],
    ['🔥 Priority Items', ':fire:'],
    ['📈 Operational Highlights', ':chart_with_upwards_trend:'],
    ['👤 Your Activity', ':bust_in_silhouette:'],
    ['⚠️ Watch Items', ':warning:'],
    ["🎯 Today's Focus", ':dart:'],
    ['✅ Wins', ':white_check_mark:'],
    ['You Completed', ':white_check_mark:'],
    ['Awaiting Your Response', ':point_right:'],
    ['Mentions', ':speech_balloon:'],
    ['Operations', ':clipboard:'],
    ['Cash Management', ':moneybag:'],
    ['Food Safety', ':apple:'],
    ['Scheduling', ':spiral_calendar_pad:'],
    ['Facilities', ':building_construction:'],
    ['Training', ':mortar_board:'],
    ['Guest Experience', ':star:']
  ]);

  let formatted = summary
    .replace(/\r\n/g, '\n')
    .replace(/^\-\s+/gm, '• ')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\*\*([^*\n]+)\*\*/g, '*$1*');

  formatted = formatted.replace(/^\*([^*\n]+)\*$/gm, (_, title) => {
    const cleanTitle = cleanString(title);
    const emoji = headingEmoji.get(cleanTitle);
    return emoji ? `${emoji} *${cleanTitle}*` : `*${cleanTitle}*`;
  });

  formatted = formatted.replace(/(^|\s)(#[a-z0-9][a-z0-9_-]*)/g, (_, prefix, channel) => {
    return `${prefix}*${channel}*`;
  });

  return formatted.replace(/\n{3,}/g, '\n\n').trim();
}

const rawTasks = Array.isArray(body.todoist_tasks) ? body.todoist_tasks : [];
const todoistTasks = rawTasks
  .map((task, index) => {
    const title = cleanString(task.title || task.content || task.summary);
    if (!title) return null;
    const source = task.source || {};
    const sourceKey = cleanString(task.source_key || task.sourceKey || buildSourceKey(task, index));
    const dueDate = cleanString(task.due_date || task.dueDate || now.slice(0, 10));
    const sourceChannel = cleanString(source.channel_name || source.channelName || source.channel_id || source.channelId);
    const permalink = cleanString(source.permalink || task.permalink);
    const summary = cleanString(task.summary || task.description || 'Action item from the morning standup.');
    const blocker = cleanString(task.blocker || task.dependency || task.blockers);
    const description = [
      summary,
      blocker ? `Blocker/Dependency: ${blocker}` : '',
      sourceChannel ? `Source Channel: ${sourceChannel}` : '',
      permalink ? `Slack Link: ${permalink}` : '',
      `Source Key: ${sourceKey}`
    ].filter(Boolean).join('\n');
    return {
      title,
      summary,
      description,
      due_date: dueDate,
      priority: Number(task.priority || 1),
      source_key: sourceKey,
      source_channel: sourceChannel,
      permalink
    };
  })
  .filter(Boolean);

const standupSummary = cleanString(body.standup_summary || body.summary || body.message);
const errors = [];
if (!standupSummary) errors.push('Missing standup_summary.');
if (!Array.isArray(body.todoist_tasks)) errors.push('Missing todoist_tasks array; use [] when there are no actionable tasks.');
if (!Array.isArray(body.excluded_channels) || !body.excluded_channels.map(cleanString).includes('general')) errors.push('excluded_channels must include general.');

return [{
  json: {
    accepted: errors.length === 0,
    errors,
    generated_at: cleanString(body.generated_at || now),
    window_start: cleanString(body.window_start || ''),
    window_end: cleanString(body.window_end || ''),
    source_workspace: cleanString(body.source_workspace || 'Chick-fil-A Brenham'),
    excluded_channels: Array.isArray(body.excluded_channels) ? body.excluded_channels : ['general'],
    standup_summary: standupSummary,
    standup_summary_slack: toSlackMrkdwn(standupSummary),
    todoist_tasks: todoistTasks,
    received_at: now
  }
}];

const payload = $('Normalize Standup Payload').first().json;
if (!payload.accepted || !payload.todoist_tasks.length) return [];

const responses = $input.all().map(item => item.json);
const existingTasks = responses.flatMap(response => {
  if (Array.isArray(response)) return response;
  if (Array.isArray(response.results)) return response.results;
  return response?.id ? [response] : [];
});

return payload.todoist_tasks.map(task => {
  const marker = `Source Key: ${task.source_key}`;
  const existing = existingTasks.find(candidate =>
    String(candidate.description || '').includes(marker) || String(candidate.content || '').includes(task.source_key)
  );
  return {
    json: {
      ...task,
      existing_id: existing?.id || '',
      has_existing_task: Boolean(existing?.id)
    }
  };
});
